#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<string> strings(n);
    for(int i = 0; i < n; i++) cin >> strings[i];
    string prefix = strings[0];
    for(int i = 1; i < n; i++){
        while(strings[i].find(prefix) != 0){
            prefix.pop_back();
            if(prefix.empty()){
                cout << -1 << endl;
                return 0;
            }
        }
    }
    cout << prefix << endl;
    return 0;
}
